import React, { useState } from 'react';
import { db } from '../firebase'; 
import { collection, query, where, getDocs } from 'firebase/firestore';
import { User, Lock, ShieldCheck, ArrowRight, AlertCircle, LayoutGrid } from 'lucide-react';

function Login({ onLogin }) {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleAuth = async (e) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    try {
      const formattedUsername = username.trim().toLowerCase();

      // 1. Querying your existing Firebase "users" collection directly
      const usersRef = collection(db, "users");
      const q = query(usersRef, where("username", "==", formattedUsername), where("password", "==", password));
      const querySnapshot = await getDocs(q);

      if (!querySnapshot.empty) {
        // 2. User found! Extract their data exactly as it is in your Firestore
        const userData = querySnapshot.docs[0].data();

        // 3. Save their exact fullName and role to local storage
        localStorage.setItem('user_info', JSON.stringify({ 
          name: userData.fullName, // Will pull "Rahul Kumar" or "Admin"
          role: userData.role,     // Will pull "student" or "admin"
          username: userData.username 
        }));

        // 4. Secure Routing based on the database role
        if (userData.role === 'admin') {
          onLogin('admin');
        } else {
          onLogin('student');
        }

      } else {
        // No match found in the database
        setError("Invalid username or password.");
      }

    } catch (err) {
      console.error("Auth Error:", err);
      setError("Failed to connect to the database. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#0a0a0a] flex flex-col justify-center items-center p-6 font-sans selection:bg-indigo-500/30">
      
      <div className="w-full max-w-md bg-white/5 backdrop-blur-xl border border-white/10 p-10 rounded-[2rem] shadow-[0_0_50px_rgba(0,0,0,0.5)] relative overflow-hidden">
        
        {/* Glow Effect */}
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-32 h-32 bg-indigo-500/30 blur-[60px] rounded-full pointer-events-none"></div>

        <div className="text-center mb-8 relative z-10">
          <div className="w-16 h-16 bg-gradient-to-tr from-indigo-500 to-purple-500 rounded-2xl mx-auto flex items-center justify-center shadow-lg mb-4 transform rotate-3">
            <LayoutGrid className="w-8 h-8 text-white transform -rotate-3" />
          </div>
          <h1 className="text-3xl font-extrabold text-white tracking-tight">CampusCanvas</h1>
          <p className="text-gray-400 text-sm mt-2">Enter your credentials to continue</p>
        </div>

        {error && (
          <div className="bg-red-500/10 border border-red-500/30 text-red-400 p-4 rounded-xl mb-6 text-sm font-medium flex items-center gap-2 animate-fade-in-up">
            <AlertCircle className="w-5 h-5 shrink-0" /> {error}
          </div>
        )}

        <form onSubmit={handleAuth} className="space-y-5 relative z-10">
          <div>
            <label className="block text-sm font-semibold text-gray-300 mb-2">Username</label>
            <div className="relative">
              <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                <User className="w-5 h-5 text-gray-500" />
              </div>
              <input 
                type="text" 
                value={username} 
                onChange={(e) => setUsername(e.target.value)} 
                className="w-full bg-black/40 border border-white/10 rounded-xl pl-12 pr-4 py-3.5 text-white outline-none focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 transition-all placeholder-gray-600 lowercase"
                placeholder="23bsccs01 or admin"
                required
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-semibold text-gray-300 mb-2">Password</label>
            <div className="relative">
              <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                <Lock className="w-5 h-5 text-gray-500" />
              </div>
              <input 
                type="password" 
                value={password} 
                onChange={(e) => setPassword(e.target.value)} 
                className="w-full bg-black/40 border border-white/10 rounded-xl pl-12 pr-4 py-3.5 text-white outline-none focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 transition-all placeholder-gray-600"
                placeholder="••••••••"
                required
              />
            </div>
          </div>

          <button 
            type="submit" 
            disabled={isLoading}
            className={`w-full mt-2 py-4 rounded-xl font-bold text-lg flex justify-center items-center gap-2 transition-all shadow-lg ${isLoading ? 'bg-gray-700 text-gray-400 cursor-not-allowed' : 'bg-indigo-600 text-white hover:bg-indigo-500 hover:shadow-[0_0_20px_rgba(79,70,229,0.4)]'}`}
          >
            {isLoading ? (
              <span className="animate-pulse">Authenticating...</span>
            ) : (
              <>Secure Login <ArrowRight className="w-5 h-5" /></>
            )}
          </button>
        </form>

        <div className="mt-8 flex items-center justify-center gap-2 text-xs text-gray-500 font-medium">
          <ShieldCheck className="w-4 h-4 text-indigo-400" /> 
          Secured by Firebase Firestore
        </div>
      </div>
    </div>
  );
}

export default Login;
